import{_ as s,C as n,c as i,o as e,a3 as o,b as d,w as a,a as l,G as h,a4 as c}from"./chunks/framework.CTM16EAR.js";const A=JSON.parse('{"title":"长期事项与待办库存","description":"用活动清单、任务追踪与标签管理周期长、目标可能变化的工作；轻量「项目 / backlog」做法，不依赖专用 PM 模块。","frontmatter":{"title":"长期事项与待办库存","description":"用活动清单、任务追踪与标签管理周期长、目标可能变化的工作；轻量「项目 / backlog」做法，不依赖专用 PM 模块。"},"headers":[],"relativePath":"guide/practices/long-horizon-inventory.md","filePath":"guide/practices/long-horizon-inventory.md","lastUpdated":1781162755000}'),g={name:"guide/practices/long-horizon-inventory.md"};function k(p,t,b,E,u,f){const r=n("Mermaid");return e(),i("div",null,[t[1]||(t[1]=o('<h1 id="长期事项与待办库存" tabindex="-1">长期事项与待办库存 <a class="header-anchor" href="#长期事项与待办库存" aria-label="Permalink to &quot;长期事项与待办库存&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">适合谁读</p><ul><li>周期 <strong>长</strong>、路径 <strong>不熟</strong>、目标 <strong>可能调整</strong> 的事（产品开发、学习一门新领域、个人 side project 等）</li><li>已会用 <a href="./../reference/activity.html">活动清单</a>、<a href="./../reference/planner.html">计划表</a>、<a href="./../reference/task.html">任务追踪</a>，想少被「今日待办」绑架，又不想让想法消失</li></ul><p>模块关系见 <a href="./../reference/workflow.html">模块联动</a>；三张清单语境见 <a href="./../pomodoro-technique/06-three-lists.html">三张清单：数字化实现</a>。</p></div><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><ul><li>这和传统 PM 有何不同：见 <a href="#轻量-backlog-是什么">轻量 backlog 是什么</a></li><li>推荐日常结构：见 <a href="#推荐结构一条无日期活动--任务清单">推荐结构一条无日期活动--任务清单</a></li><li>今天做还是以后做：见 <a href="#now-与-later-前缀">now-与-later-前缀</a></li><li>清单太长怎么办：见 <a href="#清单变长何时整理何时新开活动">清单变长何时整理何时新开活动</a></li><li>何时用子活动：见 <a href="#何时拆成子活动">何时拆成子活动</a></li><li>和冲刺 / 专注的关系：见 <a href="#和固定周期冲刺配合">和固定周期冲刺配合</a></li><li>以后可能的产品方向：见 <a href="#以后可能的产品方向">以后可能的产品方向</a></li></ul><h2 id="轻量-backlog-是什么" tabindex="-1">轻量 backlog 是什么 <a class="header-anchor" href="#轻量-backlog-是什么" aria-label="Permalink to &quot;轻量 backlog 是什么&quot;">​</a></h2><p>Pomotention <strong>没有</strong>单独的「Backlog」模块。下面做法用的是已有分层：</p><table tabindex="0"><thead><tr><th>层级</th><th>在本模式里的角色</th></tr></thead><tbody><tr><td><strong>活动 <code>activity</code>（无执行日期）</strong></td><td><strong>库存 / 收件箱</strong>：事情还 <strong>没承诺</strong> 哪一天做</td></tr><tr><td><strong>计划表 <code>todo</code>（有日期）</strong></td><td><strong>承诺</strong>：今天（或某天）真的要做的几件事</td></tr><tr><td><strong>任务 <code>task</code>（Markdown）</strong></td><td><strong>一条活动的生命周期笔记本</strong>：过程、分步、<code>- [ ]</code> / <code>- [x]</code>、能量与打扰等</td></tr><tr><td><strong>标签 <code>#</code></strong></td><td>区分主题、阶段，或在 <a href="./../reference/search.html">数据查看</a> 里筛选</td></tr></tbody></table><p>目标不是把 Pomotention 变成 Jira，而是：<strong>想法有处可放；只有下决心做的才进计划表；执行与复盘留在 Task。</strong></p>',8)),(e(),d(c,null,{default:a(()=>[h(r,{id:"mermaid-115",class:"mermaid",graph:"flowchart%20LR%0A%20%20classDef%20default%20line-height%3A1.65%0A%20%20INV%5B%22%E6%B4%BB%E5%8A%A8%E6%B8%85%E5%8D%95%3Cbr%2F%3E%E6%97%A0%E6%97%A5%E6%9C%9F%20%C2%B7%20%E6%A0%87%E7%AD%BE%20%23list%22%5D%0A%20%20TASK%5B%22%E4%BB%BB%E5%8A%A1%E8%BF%BD%E8%B8%AA%3Cbr%2F%3EMarkdown%20%E6%B8%85%E5%8D%95%22%5D%0A%20%20PLAN%5B%22%E8%AE%A1%E5%88%92%E8%A1%A8%3Cbr%2F%3E%E4%BB%8A%E6%97%A5%20todo%22%5D%0A%20%20INV%20--%3E%7C%22%E5%8F%AA%E8%AE%B0%E5%BD%95%22%7C%20TASK%0A%20%20INV%20--%3E%7C%22%E5%86%B3%E5%AE%9A%E4%BB%8A%E5%A4%A9%E5%81%9A%22%7C%20PLAN%0A%20%20PLAN%20--%3E%7C%22%E5%8B%BE%E9%80%89%E5%AE%8C%E6%88%90%22%7C%20INV%0A%20%20class%20INV%2CTASK%2CPLAN%20default%0A"})]),fallback:a(()=>t[0]||(t[0]=[l(" Loading... ")])),_:1})),t[2]||(t[2]=o(`<h2 id="推荐结构-一条无日期活动-任务清单" tabindex="-1">推荐结构：一条无日期活动 + 任务清单 <a class="header-anchor" href="#推荐结构-一条无日期活动-任务清单" aria-label="Permalink to &quot;推荐结构：一条无日期活动 + 任务清单&quot;">​</a></h2><h3 id="_1-建一条「库存」活动" tabindex="-1">1. 建一条「库存」活动 <a class="header-anchor" href="#_1-建一条「库存」活动" aria-label="Permalink to &quot;1. 建一条「库存」活动&quot;">​</a></h3><ul><li>放在 <a href="./../reference/activity.html">活动清单</a>，<strong>不要</strong>点「加入日期」（保持无 <code>dueDate</code>）。</li><li>标题示例：<code>产品待办 · list</code>、<code>Timer 14d</code>。</li><li>用 <a href="./../reference/tag.html">标签</a> 标记主题，例如 <code>#list</code>、<code>#backlog</code>、<code>#timer-now</code>（见下节）。</li></ul><h3 id="_2-在对应-task-里维护" tabindex="-1">2. 在对应 Task 里维护 <code>- [ ]</code> <a class="header-anchor" href="#_2-在对应-task-里维护" aria-label="Permalink to &quot;2. 在对应 Task 里维护 \`- [ ]\`&quot;">​</a></h3><p>从该活动进入 <a href="./../reference/task.html">任务追踪</a>，在任务描述里用 Markdown 清单：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 收件箱（未做）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">later</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] Mac 安装包签名</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] Win Timer 独立构建可安装</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 2026-05 已完成</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">x</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] 修复换天显示 bug</span></span></code></pre></div><p><strong>为何放在 Task 而不是只靠活动标题？</strong></p><ul><li>符合「<strong>Task 管一条事的整个生命周期</strong>」：从模糊想法到勾掉、附笔记。</li><li>活动标题保持短；长列表在 Task 里滚动即可。</li><li>Task 内 checkbox 可点击勾选（见任务追踪书写区）。</li></ul><p><strong>不必</strong>为了 backlog 把每条都拆成活动 <strong>子活动</strong>；子活动留给「以后要进计划表、要估 🍅」的条目（见 <a href="#何时拆成子活动">何时拆成子活动</a>）。</p><h2 id="now-与-later-前缀" tabindex="-1"><code>[now]</code> 与 <code>[later]</code> 前缀 <a class="header-anchor" href="#now-与-later-前缀" aria-label="Permalink to &quot;\`[now]\` 与 \`[later]\` 前缀&quot;">​</a></h2><p>在 <code>- [ ]</code> 文案前加前缀（自定即可，团队统一更重要）：</p><table tabindex="0"><thead><tr><th>前缀</th><th>含义</th></tr></thead><tbody><tr><td><code>[now]</code></td><td>当前阶段 <strong>允许做</strong>；可再 <strong>加入今天</strong> 的计划表</td></tr><tr><td><code>[later]</code></td><td><strong>只记录</strong>，本阶段默认不做（换 sprint、有空再做）</td></tr></tbody></table><p><strong>每日规则（防 scope 漂移）</strong></p><ol><li>计划表 <strong>今天</strong> 只从 <code>[now]</code> 里挑 <strong>1～3 条</strong> 变成 <code>todo</code>。</li><li>Activity 里只有 <code>[later]</code>、且 <strong>没进今天</strong> 的 → 默认今天 <strong>不打开</strong>。</li><li>主项目 <strong>现网 blocker</strong>（例如数据错误）可当天进 <code>todo</code>，算例外，不必先改成 <code>[now]</code>。</li></ol><p>标签可与前缀并用：例如活动打 <code>#list</code>，冲刺项在 Task 里写 <code>[now]</code>，或额外打 <code>#timer-now</code> 便于 <a href="./../reference/search.html">数据查看</a> 筛选。</p><h2 id="清单变长-何时整理、何时新开活动" tabindex="-1">清单变长：何时整理、何时新开活动 <a class="header-anchor" href="#清单变长-何时整理、何时新开活动" aria-label="Permalink to &quot;清单变长：何时整理、何时新开活动&quot;">​</a></h2><h3 id="先在同一条-task-里整理-默认" tabindex="-1">先在同一条 Task 里整理（默认） <a class="header-anchor" href="#先在同一条-task-里整理-默认" aria-label="Permalink to &quot;先在同一条 Task 里整理（默认）&quot;">​</a></h3><p><strong>不必新建活动</strong> 若：</p><ul><li>未勾条目仍 <strong>一眼能扫完</strong>（例如收件箱里少于约 15 条 <code>[ ]</code>）；</li><li>主题仍是一类事（都是同一产品待办）。</li></ul><p>做法：把已勾掉的 <code>[x]</code> <strong>剪到</strong> 文末 <code>## 已完成（年月）</code> 小节，收件箱只留未做。</p><h3 id="新开一条活动-封存-新收件箱" tabindex="-1">新开一条活动（封存 + 新收件箱） <a class="header-anchor" href="#新开一条活动-封存-新收件箱" aria-label="Permalink to &quot;新开一条活动（封存 + 新收件箱）&quot;">​</a></h3><p><strong>满足任一</strong> 即可新开，<strong>旧条保留不删</strong>（当档案）：</p><table tabindex="0"><thead><tr><th>信号</th><th>做法</th></tr></thead><tbody><tr><td>未勾条目太多，<strong>30 秒内找不到</strong> 下一件 <code>[now]</code></td><td>新建 <code>list · inbox 2026-05</code>；旧条标题改 <code>list · archive 至 2026-05</code>，Task 首行注明「新想法去 xxx」</td></tr><tr><td><strong>新阶段 / 新主题</strong>（如开始「Timer 独立安装包」冲刺）</td><td>新建 <code>Timer 14d</code> 活动；泛泛 <code>#list</code> 不再塞 sprint 项</td></tr><tr><td>一屏里 <strong><code>[x]</code> 远多于 <code>[ ]</code></strong>，心理上不想再往同页写</td><td>Task 内归档不够时，复制活动 → 新活动清空收件箱</td></tr><tr><td><strong>固定周期结束</strong>（如 14 天冲刺）</td><td>封存该 sprint 活动；日常回到 <code>list</code> 或下一轮收件箱</td></tr></tbody></table><p><strong>简单规则</strong></p><blockquote><p>还能快速找到下一件 <code>[now]</code> → 不新建。<br> 找不到，或主题换了 → 新建，旧的改名 archive。</p></blockquote><h2 id="何时拆成子活动" tabindex="-1">何时拆成子活动 <a class="header-anchor" href="#何时拆成子活动" aria-label="Permalink to &quot;何时拆成子活动&quot;">​</a></h2><table tabindex="0"><thead><tr><th>继续放在 Task 的 <code>- [ ]</code></th><th>拆成活动 <strong>子活动</strong>（或单独一条 activity）</th></tr></thead><tbody><tr><td>笔记、链接、模糊想法</td><td>已决定是 <strong>独立一事</strong></td></tr><tr><td>短期不进计划表</td><td>需要 <strong>估番茄、加入某天计划表</strong></td></tr><tr><td>在同一段 Markdown 里排序即可</td><td>要在活动清单里 <strong>拖动排序</strong>、单独打标签</td></tr></tbody></table><p>子活动仍可无日期；「承诺今天做」时再 <strong>加入日期</strong> → 计划表 <code>todo</code> → 做完在计划表 <strong>勾选</strong>，活动侧按 <a href="./../reference/workflow.html">模块联动</a> 隐藏。</p><h2 id="和固定周期冲刺配合" tabindex="-1">和固定周期冲刺配合 <a class="header-anchor" href="#和固定周期冲刺配合" aria-label="Permalink to &quot;和固定周期冲刺配合&quot;">​</a></h2><p>独立开发者 <strong>短周期冲刺</strong>（例如 14 天只交付 Windows Timer 安装包）可叠加本模式：</p><ol><li><strong>一条 sprint 活动</strong>（无日期），如 <code>Timer 14d</code>；Task 里列 <code>[now]</code> / <code>[later]</code>。</li><li><strong>泛泛 <code>#list</code></strong> 继续收长期想法，不把 sprint 和百年待办混在同一页。</li><li>冲刺结束：<strong>封存</strong> sprint 活动；<code>[later]</code> 留在 list 或下一轮收件箱。</li><li>更完整的 <strong>目标 / 不做清单 / 第 7 天砍 scope</strong> 可写在开发日志（仓库内 <code>docs/dev-log/timer-14d-anchor.md</code>），与软件内 backlog 互补。</li></ol><h2 id="以后可能的产品方向" tabindex="-1">以后可能的产品方向 <a class="header-anchor" href="#以后可能的产品方向" aria-label="Permalink to &quot;以后可能的产品方向&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">非当前操作前提</p><p>以下为 <strong>产品构想归档</strong>，<strong>不是</strong> 现在必须会的功能。当前请用本文的 <strong>标签 + 无日期活动 + Task 清单</strong> 即可。</p></div><table tabindex="0"><thead><tr><th>方向</th><th>现状（文档编写时）</th><th>说明</th></tr></thead><tbody><tr><td><strong><code>activity.projectId</code> 项目字段</strong></td><td>数据模型已有 <code>projectId</code>，界面与筛选未作为一等公民</td><td>未来或用于按「项目」聚合活动；现阶段用 <strong>标签 + 一条库存活动标题</strong> 代替</td></tr><tr><td><strong>数据查看页「文件夹 / 项目树」</strong></td><td><a href="./../reference/search.html">数据查看</a> 以搜索、标签 AND、星标为主</td><td>未来或支持按项目/文件夹浏览；现阶段用 <strong>标签筛选 + 多条 archive 活动</strong> 代替</td></tr></tbody></table><p>若实现上述能力，会在 <a href="./../intro/roadmap.html">开发地图</a> 与更新日志中说明；本文操作步骤 <strong>仍以当前版本为准</strong>。</p><h2 id="限制与说明" tabindex="-1">限制与说明 <a class="header-anchor" href="#限制与说明" aria-label="Permalink to &quot;限制与说明&quot;">​</a></h2><ul><li>无日期的活动 <strong>总会</strong> 显示在今日到期 ；库存靠 <strong>标签、归档小节、新开活动</strong> 维护。</li><li>Task 内清单 <strong>不会</strong> 自动同步到计划表；<code>[now]</code> 项要 <strong>手动加入今天</strong> 才算承诺。</li><li>本模式 <strong>不替代</strong> 番茄钟计时与当日时间表；专注执行仍用 <a href="./../reference/timer.html">番茄时钟</a> 与 <a href="./../reference/timetable.html">时间表</a>。</li></ul>`,37))])}const x=s(g,[["render",k]]);export{A as __pageData,x as default};
